/// <summary>
/// Extension of the datasource <c>InventSum</c> of the form <c>InventOnHandItem</c> for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formDataSourceStr(InventOnHandItem, InventSum))]
final class InventOnHandItem_InventSumETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Retrieves the total applied quantity for sales based on the current availability.
/// </summary>
/// <param name="_inventSum">
/// <c>InventSum</c> record.
/// </param>
/// <returns>
/// Returns the total quantity.
/// </returns>
[SysClientCacheDataMethodAttribute(true)]
display Qty ETGSPAINdisplaySalesApplicationQty(InventSum _inventSum)
{        
    InventDimParm tmpInventDimParm = element.inventDimSetupObject().parmDimParmVisibleGrid();

    return _inventSum.ETGSPAINgetSalesApplicationQty(tmpInventDimParm);
}

/// <summary>
/// Retrieves the total applied quantity for purchases based on the current availability.
/// </summary>
/// <param name="_inventSum">
/// <c>InventSum</c> record.
/// </param>
/// <returns>
/// Returns the total quantity.
/// </returns>
[SysClientCacheDataMethodAttribute(true)]
display Qty ETGSPAINdisplayPurchApplicationQty(InventSum _inventSum)
{        
    InventDimParm tmpInventDimParm = element.inventDimSetupObject().parmDimParmVisibleGrid();

    return _inventSum.ETGSPAINgetPurchApplicationQty(tmpInventDimParm);
}

/// <summary>
/// Extension of the <c>active</c> method for the ETGSPAIN model.
/// </summary>
/// <returns>
/// Returns an integer.
/// </returns>
/// <remarks>
/// This code is used to show or hide features in Spanish companies.
/// </remarks>
public int active()
{
    int     ret                             = next active();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.formRun().design().controlName(formControlStr(InventOnHandItem, ETGSPAINSalesApplicationQty)).visible(currentCompanyIsSpanishCompany);
    this.formRun().design().controlName(formControlStr(InventOnHandItem, ETGSPAINPurchApplicationQty)).visible(currentCompanyIsSpanishCompany);

    return ret;
}
